// ==============================================================
// WF1 — Preparar (monday)
// Extrai dados do item origem, gera UUID, monta dias e link,
// e prepara column_values JSON para o create_item no board histórico.
// ==============================================================

const APP_BASE_URL    = 'http://192.168.0.40'; // VM intranet (sem domínio)
const BOARD_ORIGEM_ID = 18408773953; // só para montar URL do item origem

// Colunas do board ORIGEM (mensal)
const COL_ORIGEM_CONTRATO = 'color_mktcnxwn';
const COL_ORIGEM_DATA_INI = 'date_mktayxhb';
const COL_ORIGEM_DATA_FIM = 'date_mktasnwq';
const COL_ORIGEM_NOME     = 'dropdown_mktadatt';
const COL_ORIGEM_CHAPA    = 'texto'; // Funcionário (código de chapa)

// Colunas do board HISTÓRICO (destino) — IDs verificados em 2026-04-30
const COL_HIST_UUID         = 'text_mm2xjend';
const COL_HIST_CONTRATO     = 'text_mm2x1ktb';
const COL_HIST_SOLICITANTE  = 'text_mm2xxkm8';
const COL_HIST_CHAPA        = 'text_mm33v9kp'; // Funcionário (código de chapa)
const COL_HIST_DATA_INICIO  = 'date_mm2xtp93';
const COL_HIST_DATA_FIM     = 'date_mm2xrr5q';
const COL_HIST_EXPIRA_EM    = 'date_mm2xrvt4';
const COL_HIST_CRIADO_EM    = 'date_mm2x115h';
const COL_HIST_STATUS       = 'color_mm2xkqpc';
const COL_HIST_ITEM_ORIGEM  = 'link_mm2x1rk0';
const COL_HIST_LINK_PREENCH = 'link_mm2xfay7';

const raw = $input.first().json;
const item = raw.data?.item ?? raw.item ?? raw;
const columnValues = item.column_values ?? [];
const getCol = (id) => columnValues.find(c => c.id === id);

const contrato   = getCol(COL_ORIGEM_CONTRATO)?.text || null;
const dataInicio = getCol(COL_ORIGEM_DATA_INI)?.text || null;
const dataFim    = getCol(COL_ORIGEM_DATA_FIM)?.text || null;
const nomeCol    = getCol(COL_ORIGEM_NOME);
const nome       = nomeCol?.text || item.name || 'Sem nome';
const chapa      = getCol(COL_ORIGEM_CHAPA)?.text || '';

if (!dataInicio || !dataFim) {
  throw new Error(`Item ${item.id} sem data_inicio (${dataInicio}) ou data_fim (${dataFim}).`);
}

// UUID v4 (Code node do n8n Cloud não expõe crypto global)
function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}
const uuid = uuidv4();

// Lista de dias inclusivos
const dias = [];
const atual = new Date(dataInicio + 'T00:00:00Z');
const fim = new Date(dataFim + 'T00:00:00Z');
while (atual <= fim) {
  dias.push(atual.toISOString().slice(0, 10));
  atual.setUTCDate(atual.getUTCDate() + 1);
}

const link = `${APP_BASE_URL}/preencher/${uuid}`;
const itemOrigemUrl = `https://contato-serv.monday.com/boards/${BOARD_ORIGEM_ID}/pulses/${item.id}`;

const agora = new Date();
const expiraEm = new Date(agora);
expiraEm.setUTCDate(expiraEm.getUTCDate() + 30);

function dateValue(iso, withTime) {
  if (!iso) return null;
  const d = new Date(iso);
  if (Number.isNaN(d.getTime())) return null;
  const yyyy = d.getUTCFullYear();
  const mm = String(d.getUTCMonth() + 1).padStart(2, '0');
  const dd = String(d.getUTCDate()).padStart(2, '0');
  if (!withTime) return { date: `${yyyy}-${mm}-${dd}` };
  const hh = String(d.getUTCHours()).padStart(2, '0');
  const mi = String(d.getUTCMinutes()).padStart(2, '0');
  const ss = String(d.getUTCSeconds()).padStart(2, '0');
  return { date: `${yyyy}-${mm}-${dd}`, time: `${hh}:${mi}:${ss}` };
}

// Monta o objeto column_values para o create_item
const columnValuesForCreate = {
  [COL_HIST_UUID]:         uuid,
  [COL_HIST_CONTRATO]:     contrato || '',
  [COL_HIST_SOLICITANTE]:  '', // preencha se quiser puxar do webhook event.userId
  [COL_HIST_CHAPA]:        chapa,
  [COL_HIST_DATA_INICIO]:  dateValue(dataInicio, false),
  [COL_HIST_DATA_FIM]:     dateValue(dataFim, false),
  [COL_HIST_EXPIRA_EM]:    dateValue(expiraEm.toISOString(), false),
  [COL_HIST_CRIADO_EM]:    dateValue(agora.toISOString(), true),
  [COL_HIST_STATUS]:       { label: 'Aguardando' },
  [COL_HIST_ITEM_ORIGEM]:  { url: itemOrigemUrl, text: 'Item origem' },
  [COL_HIST_LINK_PREENCH]: { url: link, text: 'Preencher' }
};

return [{
  json: {
    uuid,
    monday_item_id: String(item.id),
    nome,
    contrato,
    data_inicio: dataInicio,
    data_fim: dataFim,
    dias,
    link,
    link_text: 'Abrir formulário',
    column_values_json: JSON.stringify(columnValuesForCreate)
  }
}];
